public void testOutOfBoundsProtection() {
    NumericEntityUnescaper neu = new NumericEntityUnescaper();
    String input1 = "&";
    String result1 = neu.translate(input1);
    assertEquals("Should handle single & without error", "&", result1);

    String input2 = "&#";
    String result2 = neu.translate(input2);
    assertEquals("Should handle &# without semicolon", "&#", result2);

    String input3 = "&#x";
    String result3 = neu.translate(input3);
    assertEquals("Should handle &#x without semicolon", "&#x", result3);

    String input4 = "&#65";
    String result4 = neu.translate(input4);
    assertEquals("Should handle &#65 without semicolon", "&#65", result4);
}

public void testInvalidCodePoint() {
    NumericEntityUnescaper neu = new NumericEntityUnescaper();
    String input1 = "&#1114112;";
    String result1 = neu.translate(input1);
    assertEquals("Should not unescape invalid code point 1114112", "&#1114112;", result1);

    String input2 = "&#xFFFFFF;";
    String result2 = neu.translate(input2);
    assertEquals("Should not unescape invalid hex code point", "&#xFFFFFF;", result2);
}

public void testHexadecimalEntities() {
    NumericEntityUnescaper neu = new NumericEntityUnescaper();
    String input1 = "&#x41;";
    String expected1 = "A";
    String result1 = neu.translate(input1);
    assertEquals("Failed to unescape hex entity &#x41;", expected1, result1);

    String input2 = "&#X41;";
    String expected2 = "A";
    String result2 = neu.translate(input2);
    assertEquals("Failed to unescape hex entity &#X41;", expected2, result2);
}

public void testEmptyNumericEntity() {
    NumericEntityUnescaper neu = new NumericEntityUnescaper();
    String input1 = "&#;";
    String result1 = neu.translate(input1);
    assertEquals("Should handle empty numeric entity", "&#;", result1);

    String input2 = "&#x;";
    String result2 = neu.translate(input2);
    assertEquals("Should handle empty hex entity", "&#x;", result2);
}
